MAP
  NAME "nz-imagery"
  STATUS ON
  SIZE 256 256
  EXTENT 1756960 5914320 1757920 5915760
  UNITS METERS

  OUTPUTFORMAT
    NAME png24
    DRIVER "AGG/PNG"
    MIMETYPE "image/png"
    IMAGEMODE RGB
    EXTENSION "png"
  END

  IMAGETYPE PNG24
  IMAGECOLOR 255 255 255

  PROJECTION
    "init=epsg:2193"
  END

  WEB
    METADATA
      "wms_title"           "NZ Imagery MapServer"
      "wms_onlineresource"  "http://localhost/mapserv"
      "wms_srs"             "EPSG:2193 EPSG:4326 EPSG:3857"
      "wms_enable_request"  "*"
    END
  END

  CONFIG "MS_ERRORFILE" "stderr"
  CONFIG "AWS_NO_SIGN_REQUEST" "YES"
  CONFIG "VSI_CACHE" "TRUE"
  CONFIG "VSI_CACHE_SIZE" "50000000"
  CONFIG "GDAL_DISABLE_READDIR_ON_OPEN" "TRUE"
  CONFIG "CPL_VSIL_CURL_ALLOWED_EXTENSIONS" ".tiff,.tif"

  LAYER
    NAME "auckland-central-2023"
    TYPE RASTER
    STATUS ON
    DATA "/vsis3/nz-imagery/auckland/auckland-central_2023_0.06m/rgb/2193/BA32_2000_2202.tiff"
    PROCESSING "BANDS=1,2,3"
    PROJECTION
      "init=epsg:2193"
    END
    METADATA
      "wms_title" "Auckland Central 2023 0.06m"
    END
  END

END
